{
  "resolution_strategies": [
    {
      "resolution_strategy_id": "RS1_conditional_warning_before_initiation",
      "change_operations": [
        {
          "operation": "insert_before",
          "parameters": {
            "target_activity_label": "Initiate Account",
            "new_activity_label": "Send Warning"
          }
        },
        {
          "operation": "embed_activity_in_xor",
          "parameters": {
            "target_activity_label": "Send Warning",
            "condition": "data.balance < 0 and not data.special_allowance",
            "mode": "skip"
          }
        }
      ],
      "evaluation": {
        "compliance_degree": {
          "value": "full",
          "reason": "The inserted activity is guarded by an XOR condition matching the required condition. When data.balance < 0 and not data.special_allowance holds, Send Warning executes directly before the process continues to Initiate Account."
        },
        "resolution_context_consistency": {
          "value": "high",
          "reason": "The existing Initiate Account activity is preserved, so the context requirement exists('initiate account') remains satisfied."
        },
        "change_cost": {
          "value": "low",
          "reason": "Only two localized operations are required: inserting the warning activity and wrapping it in a conditional skip structure."
        },
        "structural_quality_impact": {
          "value": "low",
          "reason": "The process structure remains simple. A single conditional check is added immediately before account initiation without changing existing branches or activity order."
        },
        "change_location": {
          "value": "late",
          "reason": "The change is placed near the end of the process, after the initial balance handling and immediately before Initiate Account."
        }
      }
    },
    {
      "resolution_strategy_id": "RS2_conditional_warning_after_initial_deposit",
      "change_operations": [
        {
          "operation": "insert_after",
          "parameters": {
            "target_activity_label": "Accept Initial Deposit",
            "new_activity_label": "Send Warning"
          }
        },
        {
          "operation": "embed_activity_in_xor",
          "parameters": {
            "target_activity_label": "Send Warning",
            "condition": "data.balance < 0 and not data.special_allowance",
            "mode": "skip"
          }
        }
      ],
      "evaluation": {
        "compliance_degree": {
          "value": "full",
          "reason": "The required warning activity is introduced directly after the condition is evaluated in the non-special-allowance initial-deposit path. If data.balance < 0 and not data.special_allowance holds, Send Warning executes directly."
        },
        "resolution_context_consistency": {
          "value": "high",
          "reason": "The Initiate Account activity remains unchanged and continues to exist in the process."
        },
        "change_cost": {
          "value": "low",
          "reason": "The strategy requires two simple operations localized to the initial-deposit branch."
        },
        "structural_quality_impact": {
          "value": "low",
          "reason": "The added XOR skip wrapper introduces limited additional structure and does not affect the existing account-opening sequence."
        },
        "change_location": {
          "value": "late",
          "reason": "The change is applied in the later part of the process, within the balance/deposit handling section before account initiation."
        }
      }
    },
    {
      "resolution_strategy_id": "RS3_split_existing_balance_branch_with_warning",
      "change_operations": [
        {
          "operation": "add_xor_branch",
          "parameters": {
            "existing_branch_condition": "not (data.special_allowance)",
            "new_branch_condition": "data.balance < 0 and not data.special_allowance",
            "new_activity_label": "Send Warning"
          }
        },
        {
          "operation": "modify_condition",
          "parameters": {
            "target_activity_label": "Accept Initial Deposit",
            "new_condition": "not data.special_allowance and not (data.balance < 0)"
          }
        }
      ],
      "evaluation": {
        "compliance_degree": {
          "value": "substantial",
          "reason": "A branch with the required condition is added and Send Warning directly executes in that branch. However, this changes the behavior of negative-balance non-special-allowance cases because they follow the warning branch instead of the original Accept Initial Deposit branch."
        },
        "resolution_context_consistency": {
          "value": "high",
          "reason": "The strategy does not remove or rename Initiate Account, so the context requirement remains satisfied."
        },
        "change_cost": {
          "value": "medium",
          "reason": "Two operations are required, but they modify an existing XOR decision structure and alter the condition of an existing branch."
        },
        "structural_quality_impact": {
          "value": "medium",
          "reason": "The existing XOR is made more complex by adding a third branch and refining one existing condition. This may reduce readability and changes the original branch semantics."
        },
        "change_location": {
          "value": "late",
          "reason": "The modification is located in the balance acceptance section shortly before Initiate Account."
        }
      }
    },
    {
      "resolution_strategy_id": "RS4_unconditional_warning_after_initial_deposit",
      "change_operations": [
        {
          "operation": "insert_after",
          "parameters": {
            "target_activity_label": "Accept Initial Deposit",
            "new_activity_label": "Send Warning"
          }
        }
      ],
      "evaluation": {
        "compliance_degree": {
          "value": "partial",
          "reason": "Send Warning would execute after Accept Initial Deposit, including cases where the required condition may hold. However, no explicit branch with condition data.balance < 0 and not data.special_allowance is introduced, so the detected structural violation may remain unresolved."
        },
        "resolution_context_consistency": {
          "value": "high",
          "reason": "Initiate Account remains present and unchanged."
        },
        "change_cost": {
          "value": "very_low",
          "reason": "Only one insertion operation is required."
        },
        "structural_quality_impact": {
          "value": "low",
          "reason": "The structure remains simple, but the warning is executed unconditionally for all non-special-allowance initial-deposit cases, which may introduce unnecessary behavior."
        },
        "change_location": {
          "value": "late",
          "reason": "The change is located in the later balance-handling part of the process."
        }
      }
    }
  ],
  "best_resolution_strategy_id": "RS1_conditional_warning_before_initiation",
  "best_resolution_reason": "RS1 is recommended because it fully restores compliance with the condition_directly_follows requirement while preserving the existing process behavior and the context requirement exists('initiate account'). It adds only a small conditional warning step immediately before account initiation, which is the most localized and least disruptive point after balance handling."
}
